import argparse
import json
import os
import socket
import threading
import time
from typing import Dict, Tuple, List, Any

DEFAULT_BIND_HOST = "0.0.0.0"
DEFAULT_BIND_PORT = 27960
MAX_UDP_PACKET = 65507


def now_ms() -> int:
    return int(time.time() * 1000)


class GameState:
    def __init__(self):
        self.lock = threading.Lock()
        self.start_time = time.time()
        self.map_name = "arena01"
        self.game_mode = "deathmatch"
        self.server_name = "Example Game Server"
        self.max_players = 64
        self.tick_rate = 30
        self.version = "1.0.0"
        self.rules: Dict[str, Any] = {
            "friendly_fire": False,
            "time_limit": 20,
            "score_limit": 50,
            "allow_spectators": True,
        }
        self.players: List[Dict[str, Any]] = []
        self._seed_default_players()

    def _seed_default_players(self):
        sample_names = [
            "Alpha", "Bravo", "Charlie", "Delta", "Echo",
            "Foxtrot", "Golf", "Hotel", "India", "Juliet",
        ]
        with self.lock:
            for i, name in enumerate(sample_names):
                self.players.append(
                    {
                        "id": i + 1,
                        "name": name,
                        "team": "red" if i % 2 == 0 else "blue",
                        "score": (len(sample_names) - i) * 3,
                        "ping": 25 + i * 7,
                        "connected_since": time.time() - (i * 73),
                        "address": f"203.0.113.{10 + i}:27015",
                    }
                )

    def snapshot(self) -> Dict[str, Any]:
        with self.lock:
            uptime = time.time() - self.start_time
            return {
                "server_name": self.server_name,
                "version": self.version,
                "map_name": self.map_name,
                "game_mode": self.game_mode,
                "max_players": self.max_players,
                "tick_rate": self.tick_rate,
                "uptime_seconds": round(uptime, 3),
                "rules": dict(self.rules),
                "player_count": len(self.players),
                "players": [dict(p) for p in self.players],
            }


class UDPGameServer:
    def __init__(self, host: str, port: int):
        self.host = host
        self.port = port
        self.state = GameState()
        self.running = threading.Event()
        self.sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.sock.bind((self.host, self.port))

    def build_status_response(self) -> bytes:
        payload = self.state.snapshot()
        return json.dumps(payload, separators=(",", ":"), ensure_ascii=False).encode("utf-8")

    def build_error_response(self, message: str) -> bytes:
        return json.dumps({"error": message}, separators=(",", ":"), ensure_ascii=False).encode("utf-8")

    def handle_packet(self, data: bytes, addr: Tuple[str, int]):
        text = data.decode("utf-8", errors="ignore").strip().lower()
        if text in {"status", "getstatus", "info", "getinfo", "serverstatus"}:
            response = self.build_status_response()
        elif text == "ping":
            response = json.dumps({"pong": True, "time_ms": now_ms()}, separators=(",", ":")).encode("utf-8")
        elif text == "players":
            response = json.dumps({"players": self.state.snapshot()["players"]}, separators=(",", ":")).encode("utf-8")
        elif text.startswith("setmap "):
            with self.state.lock:
                self.state.map_name = text.split(" ", 1)[1].strip() or self.state.map_name
            response = json.dumps({"ok": True, "map_name": self.state.map_name}, separators=(",", ":")).encode("utf-8")
        else:
            response = self.build_error_response("unknown query")

        if len(response) <= MAX_UDP_PACKET:
            self.sock.sendto(response, addr)
        else:
            chunk_size = 1400
            total = (len(response) + chunk_size - 1) // chunk_size
            request_id = os.urandom(4).hex()
            for idx in range(total):
                chunk = response[idx * chunk_size : (idx + 1) * chunk_size]
                header = f"FRAG {request_id} {idx+1}/{total} ".encode("ascii")
                packet = header + chunk
                if len(packet) > MAX_UDP_PACKET:
                    packet = packet[:MAX_UDP_PACKET]
                self.sock.sendto(packet, addr)

    def serve_forever(self):
        self.running.set()
        while self.running.is_set():
            try:
                data, addr = self.sock.recvfrom(65535)
                threading.Thread(target=self.handle_packet, args=(data, addr), daemon=True).start()
            except OSError:
                break
            except Exception:
                continue

    def stop(self):
        self.running.clear()
        try:
            self.sock.close()
        except Exception:
            pass


def main():
    parser = argparse.ArgumentParser(description="UDP game server status responder")
    parser.add_argument("--host", default=DEFAULT_BIND_HOST)
    parser.add_argument("--port", type=int, default=DEFAULT_BIND_PORT)
    args = parser.parse_args()

    server = UDPGameServer(args.host, args.port)
    try:
        server.serve_forever()
    except KeyboardInterrupt:
        server.stop()


if __name__ == "__main__":
    main()